SELECT stimulus_id, stimulus_name, stimulus_description, stimulus_type
FROM stimuli
WHERE stimulus_type = 'visual';

SELECT user_id, username, role
FROM user_management
ORDER BY access_level DESC;

SELECT AVG(age) AS average_age
FROM participants
WHERE participation_consent = 1;

SELECT AVG(age) AS average_female_age
FROM participants
WHERE gender = 'Female';

SELECT DISTINCT participant_id
FROM outcomes
WHERE outcome_confidence_level = 'high';

SELECT * 
FROM user_management
WHERE access_level = (SELECT MAX(access_level) FROM user_management);

SELECT outcome_id, participant_id, session_id, reaction_time 
FROM outcomes 
WHERE outcome_confidence_level = 'high confidence';

SELECT AVG(age) AS average_age
FROM participants
WHERE participation_consent = 1;

SELECT participant_id FROM guesses
INTERSECT
SELECT participant_id FROM outcomes;

SELECT outcome_sigma
FROM outcomes
WHERE participant_id = 'Desired_Participant_ID';
